def get_maturity_assessment(score, dimension):
    """
    Evaluates a score and returns complete maturity assessment with descriptions
    Args:
        score (float): Score from 0-5
        dimension (str): One of the 6 assessment dimensions or 'Overall'
    Returns:
        dict: Complete assessment with level, styling, and description
    """
    # Dimension descriptions
    dimension_descriptions = {
        "Data_Strategy_Governance": {
            "Excellent": "Your data strategy is perfectly aligned with business objectives with robust governance frameworks that set industry standards.",
            "Good": "Your data strategy shows good alignment with business goals, but governance processes could be more comprehensive.",
            "Needs_Improvement": "Data strategy lacks clear alignment with business objectives and governance frameworks need significant development."
        },
        "Data_Quality_Integrity": {
            "Excellent": "Exceptional data quality with rigorous validation processes and near-perfect accuracy across all systems.",
            "Good": "Data quality is generally reliable but could benefit from more frequent validation and error detection mechanisms.",
            "Needs_Improvement": "Data quality issues are impacting operations; immediate improvement in validation and cleaning processes needed."
        },
        "Data_Driven_Decision_Intelligence": {
            "Excellent": "Data-driven decision making is deeply embedded in all business processes with advanced predictive analytics.",
            "Good": "Decisions are often informed by data, but predictive and prescriptive analytics could be more widely adopted.",
            "Needs_Improvement": "Decisions are still primarily based on intuition rather than data insights; basic analytics implementation needed."
        },
        "Data_Management_Operations": {
            "Excellent": "Flawless data operations with optimal resource allocation and seamless integration across all processes.",
            "Good": "Data operations function well but could benefit from better resource optimization and process automation.",
            "Needs_Improvement": "Inefficient data operations are causing bottlenecks; urgent process redesign and automation required."
        },
        "Data_Ethics_Privacy": {
            "Excellent": "Industry-leading ethical standards and privacy protections with comprehensive employee training programs.",
            "Good": "Solid ethical guidelines and privacy protections in place, but could benefit from more frequent compliance audits.",
            "Needs_Improvement": "Significant gaps in ethical guidelines and privacy protections pose compliance risks; immediate action needed."
        },
        "AI_Maturity_Assessment": {
            "Excellent": "AI is strategically integrated across all business functions with continuous model monitoring and optimization.",
            "Good": "AI is being successfully piloted in some areas but needs broader adoption and better governance frameworks.",
            "Needs_Improvement": "AI adoption is minimal; basic workforce training and use case identification are needed to begin maturity journey."
        },
        "Overall": {
            "Excellent": "Your organization demonstrates industry-leading data maturity across all key dimensions.",
            "Good": "Your organization shows solid data capabilities with some areas for improvement.",
            "Needs_Improvement": "Your organization has significant opportunities to improve data practices across multiple dimensions."
        }
    }

    # Determine maturity level
    if score >= 4.0:
        level = "Excellent"
    elif score >= 3.0:
        level = "Good"
    else:
        level = "Needs_Improvement"

    # Get gradient colors
    gradients = {
        "Excellent": ("#d4fddd", "#067820"),
        "Good": ("#fff3cd", "#fd7e14"),
        "Needs_Improvement": ("#f8d7da", "#dc3545")
    }

    return {
        "dimension": dimension,
        "score": score,
        "level": level,
        "description": dimension_descriptions[dimension][level],
        "css_class": level.lower().replace("_", "-"),
        "gradient": f"linear-gradient(90deg, {gradients[level][0]} 0%, {gradients[level][1]} 100%)",
        "color_start": gradients[level][0],
        "color_end": gradients[level][1]
    }

# Get input from n8n (example structure)
input_data = {    
    "Data_Strategy_Governance": items[0]["json"]["Data_Strategy_Governance"],
    "Data_Quality_Integrity": items[1]["json"]["Data_Quality_Integrity"],
    "Data_Driven_Decision_Intelligence": items[2]["json"]["Data_DrivenDecision_Intelligence"],
    "Data_Management_Operations": items[3]["json"]["Data_Management_Operations"],
    "Data_Ethics_Privacy": items[4]["json"]["Data_Ethics_Privacy"],
    "AI_Maturity_Assessment": items[5]["json"]["AI_Maturity_Assessment"]
}

# Validate input scores
for dimension, score in input_data.items():
    if not isinstance(score, (int, float)) or score < 0 or score > 5:
        raise ValueError(f"Invalid score ({score}) for {dimension}. Must be number between 0-5")

# Process all dimensions
results = []
for dimension, score in input_data.items():
    results.append(get_maturity_assessment(score, dimension))

# Calculate overall maturity
overall_score = sum(item['score'] for item in results) / len(results)
overall_assessment = get_maturity_assessment(overall_score, "Overall")

# Return in n8n format
return [{
    "json": {
        "overall": overall_assessment,
        "dimensions": results
    }
}]
